import os
import sys
import json
import argparse
import torch
import torchaudio
from torch.utils.data import DataLoader, Dataset
from model import DeepfakeDetector
from tqdm import tqdm
import glob

def find_file(filename, search_roots=None, max_depth=4):
    """Exhaustively search for a file"""
    if search_roots is None:
        search_roots = ['/data', '/rab_data', '/test_data', '/input', '/tmp', '/home', '/workspace', '/opt', '/mnt', '/']

    # Add RAB_DATA_DIR
    rab_data = os.environ.get('RAB_DATA_DIR', '')
    if rab_data:
        search_roots.insert(0, rab_data)

    # Direct check
    for root in search_roots:
        candidate = os.path.join(root, filename)
        if os.path.exists(candidate):
            return candidate

    # Recursive search
    for root in search_roots:
        if not os.path.exists(root):
            continue
        try:
            for dirpath, dirnames, filenames in os.walk(root):
                depth = dirpath.replace(root, '').count(os.sep)
                if depth > max_depth:
                    dirnames.clear()
                    continue
                if filename in filenames:
                    return os.path.join(dirpath, filename)
        except (PermissionError, OSError):
            continue

    return None

def find_dir(dirname, search_roots=None, max_depth=4):
    """Exhaustively search for a directory"""
    if search_roots is None:
        search_roots = ['/data', '/rab_data', '/test_data', '/input', '/tmp', '/home', '/workspace', '/opt', '/mnt', '/']

    rab_data = os.environ.get('RAB_DATA_DIR', '')
    if rab_data:
        search_roots.insert(0, rab_data)

    for root in search_roots:
        candidate = os.path.join(root, dirname)
        if os.path.isdir(candidate):
            return candidate

    for root in search_roots:
        if not os.path.exists(root):
            continue
        try:
            for dirpath, dirnames, filenames in os.walk(root):
                depth = dirpath.replace(root, '').count(os.sep)
                if depth > max_depth:
                    dirnames.clear()
                    continue
                if dirname in dirnames:
                    return os.path.join(dirpath, dirname)
        except (PermissionError, OSError):
            continue

    return None


def debug_fs(path, label=""):
    """Print filesystem info for debugging"""
    print(f"[DEBUG] {label} path={path} exists={os.path.exists(path)}", file=sys.stderr)
    if os.path.exists(path):
        try:
            items = sorted(os.listdir(path))[:30]
            for item in items:
                full = os.path.join(path, item)
                if os.path.isdir(full):
                    try:
                        n = len(os.listdir(full))
                        print(f"[DEBUG]   DIR: {item}/ ({n} items)", file=sys.stderr)
                    except:
                        print(f"[DEBUG]   DIR: {item}/", file=sys.stderr)
                else:
                    print(f"[DEBUG]   FILE: {item}", file=sys.stderr)
        except Exception as e:
            print(f"[DEBUG]   Error listing: {e}", file=sys.stderr)


class TestDataset(Dataset):
    def __init__(self, data_path, max_len=96000):
        self.max_len = max_len
        self.utt_ids = []
        self.flac_dir = None

        # Debug all possible data locations
        debug_fs(data_path, "data_path")
        debug_fs('/data', "/data")
        debug_fs('/rab_data', "/rab_data")
        debug_fs('/', "root")

        # Print all environment variables that might help
        for key in ['RAB_DATA_DIR', 'DATA_DIR', 'TEST_DATA', 'INPUT_DIR']:
            val = os.environ.get(key, '')
            if val:
                print(f"[DEBUG] ENV {key}={val}", file=sys.stderr)
                debug_fs(val, key)

        # Find test.txt - search broadly
        txt_path = None

        # First try direct path
        candidate = os.path.join(data_path, 'test.txt')
        if os.path.exists(candidate):
            txt_path = candidate

        # Try data_path itself as a file
        if txt_path is None and os.path.isfile(data_path) and data_path.endswith('.txt'):
            txt_path = data_path

        # Search filesystem
        if txt_path is None:
            txt_path = find_file('test.txt')

        if txt_path is None:
            # Last resort: find any .txt file that looks like an utterance list
            for root in ['/data', '/rab_data', '/test_data', '/input', '/tmp']:
                if not os.path.exists(root):
                    continue
                try:
                    for dirpath, dirnames, filenames in os.walk(root):
                        for f in filenames:
                            if f.endswith('.txt') and 'test' in f.lower():
                                txt_path = os.path.join(dirpath, f)
                                break
                        if txt_path:
                            break
                except:
                    continue
                if txt_path:
                    break

        if txt_path is None:
            raise FileNotFoundError(f"test.txt not found anywhere!")

        print(f"[DEBUG] Found test.txt: {txt_path}", file=sys.stderr)

        with open(txt_path, 'r') as f:
            for line in f:
                utt_id = line.strip()
                if utt_id:
                    self.utt_ids.append(utt_id)

        print(f"[DEBUG] Loaded {len(self.utt_ids)} utterance IDs", file=sys.stderr)

        # Find flac directory
        flac_dir = None

        # Try relative to test.txt location
        txt_dir = os.path.dirname(txt_path)
        candidate = os.path.join(txt_dir, 'flac')
        if os.path.isdir(candidate):
            flac_dir = candidate

        # Try data_path
        if flac_dir is None and os.path.exists(data_path):
            candidate = os.path.join(data_path, 'flac')
            if os.path.isdir(candidate):
                flac_dir = candidate

        # Search filesystem
        if flac_dir is None:
            flac_dir = find_dir('flac')

        if flac_dir is None:
            raise FileNotFoundError(f"flac directory not found anywhere!")

        self.flac_dir = flac_dir
        print(f"[DEBUG] Found flac dir: {flac_dir}", file=sys.stderr)

        # Verify a sample file exists
        if self.utt_ids:
            sample_path = os.path.join(self.flac_dir, f'{self.utt_ids[0]}.flac')
            if os.path.exists(sample_path):
                print(f"[DEBUG] Sample file exists: {sample_path}", file=sys.stderr)
            else:
                print(f"[DEBUG] WARNING: Sample file NOT found: {sample_path}", file=sys.stderr)

    def __len__(self):
        return len(self.utt_ids)

    def __getitem__(self, idx):
        utt_id = self.utt_ids[idx]
        flac_path = os.path.join(self.flac_dir, f'{utt_id}.flac')
        wav, sr = torchaudio.load(flac_path)
        wav = wav.squeeze(0)
        if sr != 16000:
            wav = torchaudio.functional.resample(wav, sr, 16000)
        orig_len = min(wav.shape[0], self.max_len)
        if wav.shape[0] > self.max_len:
            wav = wav[:self.max_len]
        elif wav.shape[0] < self.max_len:
            wav = torch.nn.functional.pad(wav, (0, self.max_len - wav.shape[0]))
        return wav, utt_id, orig_len


def collate_fn(batch):
    wavs, utt_ids, orig_lens = zip(*batch)
    wavs = torch.stack(wavs)
    B, T = wavs.shape
    attention_mask = torch.zeros(B, T, dtype=torch.long)
    for i, l in enumerate(orig_lens):
        attention_mask[i, :l] = 1
    return wavs, utt_ids, attention_mask


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    parser.add_argument('--batch_size', type=int, default=96)
    parser.add_argument('--num_workers', type=int, default=4)
    args = parser.parse_args()

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')

    ckpt = torch.load(args.checkpoint, map_location=device, weights_only=False)
    ckpt_args = ckpt.get('args', {})
    encoder_name = ckpt_args.get('encoder', 'microsoft/wavlm-large')
    freeze_layers = ckpt_args.get('freeze_layers', 16)
    pooling = ckpt_args.get('pooling', 'mean')
    max_len = ckpt_args.get('max_len', 96000)

    print(f"[DEBUG] Checkpoint args: {ckpt_args}", file=sys.stderr)
    print(f"[DEBUG] Using encoder={encoder_name}, freeze={freeze_layers}, pooling={pooling}", file=sys.stderr)

    model = DeepfakeDetector(
        encoder_name=encoder_name,
        freeze_layers=freeze_layers,
        pooling=pooling
    ).to(device)

    model.load_state_dict(ckpt['model_state_dict'])
    model.eval()

    test_ds = TestDataset(args.data_path, max_len=max_len)
    test_loader = DataLoader(
        test_ds, batch_size=args.batch_size, shuffle=False,
        num_workers=args.num_workers, collate_fn=collate_fn, pin_memory=True
    )

    predictions = []
    utt_order = []

    with torch.no_grad():
        for wavs, utt_ids, att_mask in tqdm(test_loader, desc='Predicting'):
            wavs = wavs.to(device)
            att_mask = att_mask.to(device)
            with torch.amp.autocast('cuda', dtype=torch.bfloat16):
                logits = model(wavs, attention_mask=att_mask)
            scores = logits.float().cpu().numpy().tolist()
            predictions.extend(scores)
            utt_order.extend(utt_ids)

    # Reorder predictions to match test.txt order
    utt_to_score = dict(zip(utt_order, predictions))
    ordered_scores = [utt_to_score[uid] for uid in test_ds.utt_ids]

    result = {"predictions": ordered_scores}
    with open(args.output, 'w') as f:
        json.dump(result, f)

    print(f"[DEBUG] Wrote {len(ordered_scores)} predictions to {args.output}", file=sys.stderr)


if __name__ == '__main__':
    main()
